def gate_rate(n_accept, n_review, n_reject):
    n_total = n_accept + n_review + n_reject
    if n_total == 0:
        return None
    return {
        "reject_rate": n_reject / n_total,
        "review_rate": n_review / n_total,
        "accept_rate": n_accept / n_total,
        "n_total": n_total,
    }
print(gate_rate(80, 15, 5))

def run_gate(rows):
    out = []
    for r in rows:
        if r.get("edad") is None:
            out.append("review")
        elif r["edad"] < 18:
            out.append("reject")
        else:
            out.append("accept")
    return out
print(run_gate([{"edad": 20}, {"edad": None}, {"edad": 10}]))
